export const ERROR_CODES = {
  GPU_UNAVAILABLE: 'DOPPLER_GPU_UNAVAILABLE',
  GPU_DEVICE_FAILED: 'DOPPLER_GPU_DEVICE_FAILED',
  GPU_OOM: 'DOPPLER_GPU_OOM',
  GPU_DEVICE_LOST: 'DOPPLER_GPU_DEVICE_LOST',
  GPU_TIMEOUT: 'DOPPLER_GPU_TIMEOUT',
  GPU_UNSUPPORTED_ADAPTER: 'DOPPLER_GPU_UNSUPPORTED_ADAPTER',
  PROVIDER_LOCAL_FAILED: 'DOPPLER_PROVIDER_LOCAL_FAILED',
  PROVIDER_FALLBACK_FAILED: 'DOPPLER_PROVIDER_FALLBACK_FAILED',
  PROVIDER_FALLBACK_NOT_CONFIGURED: 'DOPPLER_PROVIDER_FALLBACK_NOT_CONFIGURED',
  PROVIDER_POLICY_DENIED: 'DOPPLER_PROVIDER_POLICY_DENIED',
  PROVIDER_NETWORK_FAILED: 'DOPPLER_PROVIDER_NETWORK_FAILED',
  LOADER_MANIFEST_INVALID: 'DOPPLER_LOADER_MANIFEST_INVALID',
  LOADER_SHARD_INDEX_INVALID: 'DOPPLER_LOADER_SHARD_INDEX_INVALID',
  DISTRIBUTION_P2P_CONTRACT_UNSUPPORTED: 'DOPPLER_DISTRIBUTION_P2P_CONTRACT_UNSUPPORTED',
  DISTRIBUTION_P2P_TRANSPORT_UNCONFIGURED: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_UNCONFIGURED',
  DISTRIBUTION_P2P_TRANSPORT_UNAVAILABLE: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_UNAVAILABLE',
  DISTRIBUTION_P2P_TRANSPORT_TIMEOUT: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_TIMEOUT',
  DISTRIBUTION_P2P_TRANSPORT_ABORTED: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_ABORTED',
  DISTRIBUTION_P2P_TRANSPORT_INTEGRITY_MISMATCH: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_INTEGRITY_MISMATCH',
  DISTRIBUTION_P2P_TRANSPORT_POLICY_DENIED: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_POLICY_DENIED',
  DISTRIBUTION_P2P_TRANSPORT_INTERNAL: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_INTERNAL',
  DISTRIBUTION_P2P_TRANSPORT_PAYLOAD_INVALID: 'DOPPLER_DISTRIBUTION_P2P_TRANSPORT_PAYLOAD_INVALID',
  DISTRIBUTION_SHARD_HASH_MISMATCH: 'DOPPLER_DISTRIBUTION_SHARD_HASH_MISMATCH',
  DISTRIBUTION_SHARD_SIZE_MISMATCH: 'DOPPLER_DISTRIBUTION_SHARD_SIZE_MISMATCH',
  DISTRIBUTION_SHARD_MANIFEST_VERSION_SET_MISMATCH: 'DOPPLER_DISTRIBUTION_SHARD_MANIFEST_VERSION_SET_MISMATCH',
  DISTRIBUTED_PLAN_STALE: 'DOPPLER_DISTRIBUTED_PLAN_STALE',
  DISTRIBUTED_PLAN_INVALID: 'DOPPLER_DISTRIBUTED_PLAN_INVALID',
  DISTRIBUTED_PLAN_ARTIFACT_MISMATCH: 'DOPPLER_DISTRIBUTED_PLAN_ARTIFACT_MISMATCH',
  DISTRIBUTED_PLAN_TOPOLOGY_UNFIT: 'DOPPLER_DISTRIBUTED_PLAN_TOPOLOGY_UNFIT',
  DISTRIBUTED_PLAN_UNSUPPORTED: 'DOPPLER_DISTRIBUTED_PLAN_UNSUPPORTED',
  COLLECTIVE_BUFFER_EXHAUSTED: 'DOPPLER_COLLECTIVE_BUFFER_EXHAUSTED',
  COLLECTIVE_TIMEOUT: 'DOPPLER_COLLECTIVE_TIMEOUT',
  COLLECTIVE_ABORTED: 'DOPPLER_COLLECTIVE_ABORTED',
  COLLECTIVE_PAYLOAD_INVALID: 'DOPPLER_COLLECTIVE_PAYLOAD_INVALID',
  COLLECTIVE_INTEGRITY_MISMATCH: 'DOPPLER_COLLECTIVE_INTEGRITY_MISMATCH',
  DISTRIBUTED_STAGE_UNRECOVERABLE: 'DOPPLER_DISTRIBUTED_STAGE_UNRECOVERABLE',
};

// Validate that all error code values are unique at module init time.
// Duplicate values would cause ambiguous error identification.
const seenCodeValues = new Set();
for (const [key, value] of Object.entries(ERROR_CODES)) {
  if (seenCodeValues.has(value)) {
    throw new Error(`DopplerError: duplicate error code value "${value}" for key "${key}".`);
  }
  seenCodeValues.add(value);
}

export function createDopplerError(code, message) {
  if (!seenCodeValues.has(code)) {
    throw new Error(`DopplerError: unknown error code "${code}". Register it in ERROR_CODES first.`);
  }
  const error = new Error(`[${code}] ${message}`);
  error.code = code;
  return error;
}
